import { useState } from "react";

function Upload({ onUpload, isUploading, uploadProgressLabel, maxFileSizeLabel }) {
  const [selectedFile, setSelectedFile] = useState(null);
  const [customName, setCustomName] = useState("");
  const [isDragActive, setIsDragActive] = useState(false);

  const selectFile = (file) => {
    setSelectedFile(file || null);

    setCustomName(file ? file.name : "");
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    const form = event.currentTarget;

    if (!selectedFile) {
      return;
    }

    const wasSuccessful = await onUpload(selectedFile, customName);

    if (wasSuccessful) {
      setSelectedFile(null);
      setCustomName("");
      form.reset();
    }
  };

  return (
    <section className="panel panel-highlight">
      <h2>Upload File</h2>
      <p className="panel-copy">
        Choose a file, give it a workspace-friendly name, and send it through the
        secure direct-to-S3 upload flow.
      </p>

      <form onSubmit={handleSubmit} className="stack">
        <label
          className={`file-picker ${isDragActive ? "drag-active" : ""}`}
          onDragOver={(event) => {
            event.preventDefault();
            setIsDragActive(true);
          }}
          onDragLeave={() => setIsDragActive(false)}
          onDrop={(event) => {
            event.preventDefault();
            setIsDragActive(false);
            selectFile(event.dataTransfer.files?.[0] || null);
          }}
        >
          <div className="upload-visual">+</div>
          <div className="upload-copy">
            <strong>{selectedFile ? selectedFile.name : "Drag and drop a file"}</strong>
            <span>
              {selectedFile
                ? "Ready for secure upload."
                : `or click to browse. Maximum size ${maxFileSizeLabel}.`}
            </span>
          </div>
          <input
            type="file"
            onChange={(event) => selectFile(event.target.files?.[0] || null)}
          />
        </label>

        <input
          className="text-input"
          type="text"
          placeholder="Custom file name shown in your workspace"
          value={customName}
          onChange={(event) => setCustomName(event.target.value)}
          disabled={!selectedFile}
        />

        {selectedFile && (
          <div className="file-meta-card">
            <span>Upload summary</span>
            <strong>{customName.trim() || selectedFile.name}</strong>
            <p>
              Original: {selectedFile.name} • {(selectedFile.type || "Unknown type").replace("/", " / ")}
              {" "}• {Math.max(selectedFile.size / 1024, 1).toFixed(1)} KB
            </p>
          </div>
        )}

        {uploadProgressLabel && <div className="inline-status">{uploadProgressLabel}</div>}

        <button type="submit" className="primary-button" disabled={!selectedFile || isUploading}>
          {isUploading ? "Uploading Securely..." : "Upload to Workspace"}
        </button>
      </form>
    </section>
  );
}

export default Upload;
